INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'naperville'), 'R1A', 'r1a', 'Low Density Single-Family Residence District', 'This district is intended to provide for low density single-family residential development and to accommodate various public and recreational uses.', 35, NULL, 10000, 40, 30, 30, 6, 'Refer to Chapter 9 of the Naperville Municipal Code; for single-family detached dwellings, 2 spaces per dwelling unit.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'r1a' AND z.city_id = (SELECT id FROM cities WHERE slug = 'naperville') AND pu.name IN ('Single-family detached dwellings', 'Primary and secondary schools (without boarding facilities)', 'Preschools (accessory to primary/secondary schools)', 'Golf courses', 'Parks, playgrounds, and forest preserves', 'Residential care homes') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'naperville'), 'R1B', 'r1b', 'Medium Density Single-Family Residence District', 'This district is intended to provide for medium density single-family residential development and to accommodate various public and recreational uses.', 35, NULL, 7200, 45, 30, 30, 6, 'Refer to Chapter 9 of the Naperville Municipal Code; for single-family detached dwellings, 2 spaces per dwelling unit.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
